#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; long long M,K; scanf("%d %lld %lld",&N,&M,&K);
        long long a, last=0;
        for(int i=0;i<N;i++){
            scanf("%lld",&a);
            if(i==N-1) last=a;
        }
        if(last + K - 1 <= M) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

