import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); K = int(next(it))
        last = 0
        for i in range(N):
            a = int(next(it))
            if i == N-1:
                last = a
        out.append('Yes' if last + K - 1 <= M else 'No')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

